// src/pages/HomeScreen.js
import React, { useMemo, useState } from "react";
import {
  SafeAreaView,
  View,
  Text,
  StyleSheet,
  Image,
  TextInput,
  TouchableOpacity,
  ScrollView,
  Platform,
  useWindowDimensions,
} from "react-native";

const nalicoreLogo = require("../../assets/nalicore_logo.png");

export default function HomeScreen() {
  const { width } = useWindowDimensions();

  // Keep the original: input + button on same row on normal phones.
  // Only stack on very tiny widths (rare).
  const stackSearch = width < 360;

  // center container on web/tablet like the original mock
  const maxWidth = width >= 1024 ? 760 : width >= 768 ? 720 : "100%";

  const [query, setQuery] = useState(
    "Total borne 10 entre\nenfant noir chez le boss"
  );

  const resolved = useMemo(
    () => ({
      quartier: "Odza",
      secteur: "Borne 10",
      sousSecteur: "Total borne 10",
      entree: "Enfant Noir",
      lieu: "Chez le Boss",
      banoc: "Q5TCL",
      latitude: 3.7862,
      longitude: 111.53045,
    }),
    []
  );

  const onResolve = () => console.log("Resolve:", query);
  const onNavigate = () =>
    console.log("Navigate:", resolved.latitude, resolved.longitude);

  return (
    <SafeAreaView style={styles.safe}>
      <ScrollView
        contentContainerStyle={styles.scroll}
        showsVerticalScrollIndicator={false}
        keyboardShouldPersistTaps="handled"
      >
        <View style={[styles.container, { maxWidth }]}>
          {/* Header (match original spacing + alignment) */}
          <View style={styles.header}>
            <Image source={nalicoreLogo} style={styles.logo} resizeMode="contain" />
            <Text style={styles.tagline}>
              Natural Address{"\n"}Location Infrastructure
            </Text>
          </View>

          {/* Search row (NO WRAP like original) */}
          <View
            style={[
              styles.searchRow,
              { flexDirection: stackSearch ? "column" : "row" },
            ]}
          >
            <View style={[styles.searchInputWrap, stackSearch && { width: "100%" }]}>
              <Text style={styles.searchIcon}>⌕</Text>

              <TextInput
                value={query}
                onChangeText={setQuery}
                style={styles.searchInput}
                placeholder="Type an address…"
                placeholderTextColor="rgba(15,23,42,0.42)"
                multiline
                numberOfLines={2}
                scrollEnabled={false} // prevents ugly inner scrolling
                textAlignVertical="center"
              />
            </View>

            <TouchableOpacity
              activeOpacity={0.9}
              style={[
                styles.resolveBtn,
                stackSearch ? { width: 180, alignSelf: "flex-start" } : null,
              ]}
              onPress={onResolve}
            >
              <Text style={styles.resolveText}>Resolve</Text>
            </TouchableOpacity>
          </View>

          {/* Card (spacing + font weights tuned to original) */}
          <View style={styles.card}>
            <Text style={styles.cardTitle}>Resolved Address</Text>

            <Row label="Quartier:" value={resolved.quartier} />
            <Row label="Secteur:" value={resolved.secteur} />
            <Row label="Sous-secteur:" value={resolved.sousSecteur} />
            <Row label="Entrée:" value={resolved.entree} />
            <Row label="Lieu:" value={resolved.lieu} />

            <View style={styles.row}>
              <Text style={styles.label}>BANOC:</Text>
              <View style={styles.banocPill}>
                <Text style={styles.banocText}>{resolved.banoc}</Text>
              </View>
            </View>

            {/* IMPORTANT: single-value lat/lng only */}
            <Row label="Latitude:" value={Number(resolved.latitude).toFixed(5)} />
            <Row label="Longitude:" value={Number(resolved.longitude).toFixed(5)} />

            <TouchableOpacity activeOpacity={0.9} style={styles.navBtn} onPress={onNavigate}>
              <Text style={styles.navIcon}>⌖</Text>
              <Text style={styles.navText}>Navigate to Location</Text>
            </TouchableOpacity>
          </View>

          <View style={{ height: 240 }} />
        </View>
      </ScrollView>
    </SafeAreaView>
  );
}

function Row({ label, value }) {
  return (
    <View style={styles.row}>
      <Text style={styles.label}>{label}</Text>
      <Text style={styles.value}>{value}</Text>
    </View>
  );
}

const styles = StyleSheet.create({
  safe: { flex: 1, backgroundColor: "#E9ECF6" },
  scroll: { paddingBottom: 30 },

  // Center the whole UI on wide screens like the original mock
  container: {
    width: "100%",
    alignSelf: "center",
    paddingHorizontal: 22,
    paddingTop: 22,
  },

  header: {
    flexDirection: "row",
    alignItems: "flex-start",
    justifyContent: "space-between",
    marginBottom: 18,
  },
  logo: { width: 190, height: 54 },
  tagline: {
    textAlign: "right",
    color: "rgba(15, 23, 42, 0.62)",
    fontSize: 18,
    fontWeight: "700",
    lineHeight: 26,
  },

  // Keep same-row layout and proportions
  searchRow: {
    alignItems: "stretch",
    gap: 12,
    marginBottom: 18,
  },

  searchInputWrap: {
    flex: 1,
    minHeight: 68,
    borderRadius: 18,
    backgroundColor: "rgba(255,255,255,0.70)",
    borderWidth: 1,
    borderColor: "rgba(15,23,42,0.08)",
    paddingLeft: 50,
    paddingRight: 14,
    justifyContent: "center",
    ...Platform.select({
      ios: {
        shadowColor: "#000",
        shadowOpacity: 0.06,
        shadowRadius: 14,
        shadowOffset: { width: 0, height: 10 },
      },
      android: { elevation: 2 },
    }),
  },
  searchIcon: {
    position: "absolute",
    left: 18,
    top: 22,
    fontSize: 18,
    color: "rgba(15, 23, 42, 0.42)",
  },
  searchInput: {
    fontSize: 24,          // closer to original
    fontWeight: "800",
    color: "#0F172A",
    lineHeight: 30,
    paddingVertical: 8,
  },

  resolveBtn: {
    width: 150,
    minHeight: 68,
    borderRadius: 18,
    backgroundColor: "#2E59B7",
    alignItems: "center",
    justifyContent: "center",
    ...Platform.select({
      ios: {
        shadowColor: "#000",
        shadowOpacity: 0.10,
        shadowRadius: 16,
        shadowOffset: { width: 0, height: 12 },
      },
      android: { elevation: 4 },
    }),
  },
  resolveText: {
    color: "#FFFFFF",
    fontSize: 22,
    fontWeight: "900",
    letterSpacing: 0.2,
  },

  card: {
    borderRadius: 22,
    padding: 22,
    backgroundColor: "rgba(255,255,255,0.70)",
    borderWidth: 1,
    borderColor: "rgba(15,23,42,0.08)",
    ...Platform.select({
      ios: {
        shadowColor: "#000",
        shadowOpacity: 0.08,
        shadowRadius: 18,
        shadowOffset: { width: 0, height: 14 },
      },
      android: { elevation: 3 },
    }),
  },
  cardTitle: {
    fontSize: 34,          // original title is BIG
    fontWeight: "900",
    color: "#0F172A",
    marginBottom: 16,
  },

  row: {
    flexDirection: "row",
    alignItems: "center",
    marginBottom: 14,
  },

  // tuned weights: labels lighter, values bold but not insane
  label: {
    width: 150,
    fontSize: 24,
    fontWeight: "800",
    color: "rgba(15,23,42,0.45)",
  },
  value: {
    flex: 1,
    fontSize: 28,
    fontWeight: "900",
    color: "#0F172A",
  },

  banocPill: {
    borderRadius: 16,
    paddingHorizontal: 16,
    paddingVertical: 10,
    backgroundColor: "rgba(46,89,183,0.12)",
    borderWidth: 1,
    borderColor: "rgba(46,89,183,0.20)",
  },
  banocText: {
    color: "#2E59B7",
    fontSize: 24,
    fontWeight: "900",
    letterSpacing: 1,
  },

  navBtn: {
    marginTop: 18,
    height: 80,
    borderRadius: 22,
    backgroundColor: "#2E59B7",
    alignItems: "center",
    justifyContent: "center",
    flexDirection: "row",
    gap: 12,
    ...Platform.select({
      ios: {
        shadowColor: "#000",
        shadowOpacity: 0.12,
        shadowRadius: 18,
        shadowOffset: { width: 0, height: 14 },
      },
      android: { elevation: 5 },
    }),
  },
  navIcon: { color: "#FFFFFF", fontSize: 22, marginTop: -1 },
  navText: { color: "#FFFFFF", fontSize: 28, fontWeight: "900" },
});
